/**
 * @public
 */
export const parse = async (source, {
  sourceMap = false
} = {}) => {
  const cst = await lexicalAnalysis(source);
  try {
    return syntacticAnalysis(cst, {
      sourceMap
    });
  } finally {
    cst.delete();
  }
};